/**
 * Unit tests for posttool/context-crossing-warn hook (Issue #1470)
 *
 * Cumulative-token accumulator. First crossing of threshold emits an
 * additionalContext warning; subsequent tool calls in the same session are
 * silent. State is per-session so a new session auto-re-arms.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
  mkdirSync: vi.fn(),
}));

// Hoisted so it's available when vi.mock (which is itself hoisted) runs.
const { atomicWriteMock } = vi.hoisted(() => ({ atomicWriteMock: vi.fn() }));
vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: atomicWriteMock,
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { contextCrossingWarn } from '../../posttool/context-crossing-warn.js';
import { existsSync, readFileSync } from 'node:fs';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

const PROJECT_DIR = '/test/project';

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Read',
    session_id: 'sess-A',
    tool_input: {},
    tool_output: 'x'.repeat(4000), // ~1000 tokens at 1 token / 4 chars
    ...overrides,
  };
}

function lastWrittenState(): {
  estimatedTokens: number;
  crossings: Record<string, boolean>;
  lastToolName?: string;
} {
  expect(atomicWriteMock).toHaveBeenCalled();
  const lastCall = atomicWriteMock.mock.calls[atomicWriteMock.mock.calls.length - 1];
  return JSON.parse(String(lastCall[1]));
}

describe('contextCrossingWarn', () => {
  let ctx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    atomicWriteMock.mockClear();
    ctx = createTestContext({ projectDir: PROJECT_DIR, sessionId: 'sess-A' });
    delete process.env.ORK_NO_CTX_WARN;
    delete process.env.ORK_CTX_WARN_THRESHOLD;
  });

  afterEach(() => {
    delete process.env.ORK_NO_CTX_WARN;
    delete process.env.ORK_CTX_WARN_THRESHOLD;
  });

  describe('accumulation + first-crossing fire', () => {
    it('stays silent while under threshold', () => {
      vi.mocked(existsSync).mockReturnValue(false);

      const result = contextCrossingWarn(makeInput({ tool_output: 'small' }), ctx);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });

    it('fires once when accumulation crosses threshold', () => {
      // Priming state file = tokens 149_990 (just under 150k default)
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 149_990,
          crossings: {},
          updatedAt: new Date().toISOString(),
        }),
      );

      // 4000-char output ≈ 1000 added tokens → pushes to ~150,990
      const result = contextCrossingWarn(makeInput(), ctx);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('150,000');
      expect(result.hookSpecificOutput?.additionalContext).toContain('/clear');
      expect(result.hookSpecificOutput?.additionalContext).toContain('/compact');

      const state = lastWrittenState();
      expect(state.crossings['150000']).toBe(true);
      expect(state.estimatedTokens).toBeGreaterThanOrEqual(150_000);
    });

    it('stays silent on the NEXT call in the same session after firing', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 151_000,
          crossings: { '150000': true },
          updatedAt: new Date().toISOString(),
        }),
      );

      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });
  });

  describe('session re-arm', () => {
    it('re-arms for a new session id (no state file)', () => {
      // First session crossed and flagged — but new session has no state file
      vi.mocked(existsSync).mockReturnValue(false);

      // Make one big tool call that alone crosses the threshold (600k chars ≈ 150k tokens)
      const bigInput = makeInput({
        session_id: 'sess-B',
        tool_output: 'y'.repeat(600_000),
      });
      const freshCtx = createTestContext({ projectDir: PROJECT_DIR, sessionId: 'sess-B' });

      const result = contextCrossingWarn(bigInput, freshCtx);

      expect(result.hookSpecificOutput?.additionalContext).toContain('crossed');
      expect(lastWrittenState().crossings['150000']).toBe(true);
    });
  });

  describe('env threshold override', () => {
    it('respects ORK_CTX_WARN_THRESHOLD for a lower trip point', () => {
      process.env.ORK_CTX_WARN_THRESHOLD = '5000';
      vi.mocked(existsSync).mockReturnValue(false);

      // 20_000 chars ≈ 5_000 tokens → crosses the 5k threshold
      const result = contextCrossingWarn(
        makeInput({ tool_output: 'z'.repeat(20_000) }),
        ctx,
      );

      expect(result.hookSpecificOutput?.additionalContext).toContain('5,000');
      expect(lastWrittenState().crossings['5000']).toBe(true);
    });

    it('falls back to 150k when threshold env is invalid', () => {
      process.env.ORK_CTX_WARN_THRESHOLD = 'not-a-number';
      vi.mocked(existsSync).mockReturnValue(false);

      const result = contextCrossingWarn(
        makeInput({ tool_output: 'x'.repeat(4000) }),
        ctx,
      );

      // Small output, well under 150k → silent
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });
  });

  describe('opt-out', () => {
    it('is fully silent when ORK_NO_CTX_WARN=1', () => {
      process.env.ORK_NO_CTX_WARN = '1';

      const result = contextCrossingWarn(
        makeInput({ tool_output: 'x'.repeat(1_000_000) }),
        ctx,
      );

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
      expect(atomicWriteMock).not.toHaveBeenCalled();
    });
  });

  describe('input shape handling', () => {
    it('estimates from tool_result string', () => {
      vi.mocked(existsSync).mockReturnValue(false);

      const result = contextCrossingWarn(
        {
          tool_name: 'Read',
          session_id: 'sess-A',
          tool_input: {},
          tool_result: 'x'.repeat(800_000),
        } as HookInput,
        ctx,
      );

      expect(result.hookSpecificOutput?.additionalContext).toBeDefined();
    });

    it('estimates from tool_result object with content field', () => {
      vi.mocked(existsSync).mockReturnValue(false);

      const result = contextCrossingWarn(
        {
          tool_name: 'Skill',
          session_id: 'sess-A',
          tool_input: {},
          tool_result: { is_error: false, content: 'a'.repeat(800_000) },
        } as HookInput,
        ctx,
      );

      expect(result.hookSpecificOutput?.additionalContext).toBeDefined();
    });

    it('handles corrupt state file gracefully and resets accumulator', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue('not valid json');

      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(lastWrittenState().estimatedTokens).toBeGreaterThan(0);
    });
  });
});
